#include<stdio.h>
long long cnt=0;
void merge(int*a,int lo,int mid,int hi){int tmp[100001],i=lo,j=mid,k=0;while(i<mid&&j<hi){if(a[i]<=a[j])tmp[k++]=a[i++];else{tmp[k++]=a[j++];cnt+=mid-i;}}while(i<mid)tmp[k++]=a[i++];while(j<hi)tmp[k++]=a[j++];for(int x=0;x<k;x++)a[lo+x]=tmp[x];}
void msort(int*a,int lo,int hi){if(hi-lo<2)return;int mid=(lo+hi)/2;msort(a,lo,mid);msort(a,mid,hi);merge(a,lo,mid,hi);}
int main(){int n;scanf("%d",&n);int a[100001];for(int i=0;i<n;i++)scanf("%d",&a[i]);msort(a,0,n);printf("%lld\n",cnt);}
